function stripLength(startTri: number, startV: number): number {
  let m1 = verts[(startV + 2) % 3];
  let m2 = verts[(startV + 1) % 3];
  used[startTri] = 2;
  let count = 1;

  outer:
  for (let j = startTri + 1; j < numTris; j++) {
    for (let k = 0; k < 3; k++) {
      if (tris[j][k] !== m1) continue;
      if (tris[j][(k + 1) % 3] !== m2) continue;
      if (used[j]) break outer; // strip done
      if (count & 1) m2 = tris[j][(k + 2) % 3];
      else m1 = tris[j][(k + 2) % 3];
      used[j] = 2;
      count++;
      continue outer;
    }
  }

  for (let j = startTri + 1; j < numTris; j++)
    if (used[j] === 2) used[j] = 0;

  return count;
}
